eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   LESSON_CONTENT_MAP: () => (/* binding */ LESSON_CONTENT_MAP),\n/* harmony export */   MODULE_1_CONTENT: () => (/* binding */ MODULE_1_CONTENT),\n/* harmony export */   MODULE_2_CONTENT: () => (/* binding */ MODULE_2_CONTENT),\n/* harmony export */   MODULE_3_CONTENT: () => (/* binding */ MODULE_3_CONTENT),\n/* harmony export */   MODULE_4_CONTENT: () => (/* binding */ MODULE_4_CONTENT),\n/* harmony export */   MODULE_5_CONTENT: () => (/* binding */ MODULE_5_CONTENT)\n/* harmony export */ });\n// src/lib/lesson-content.ts\n// Contenido enriquecido de lecciones con imágenes, ejemplos reales, callouts y ejercicios\n// ─────────────────────────────────────────────\n// MÓDULO 1 — MENTALIDAD Y REALIDAD\n// ─────────────────────────────────────────────\nconst MODULE_1_CONTENT = {\n    \"leccion-1-1\": [\n        {\n            type: \"quote\",\n            content: \"No soy guru. No soy coach motivacional. Soy un operador que construy\\xf3 algo real y te est\\xe1 mostrando exactamente c\\xf3mo lo hizo.\",\n            author: \"Jose Angel\",\n            role: \"Fundador, Freedom AI\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Los n\\xfameros reales, sin filtros\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Antes de ense\\xf1arte cualquier cosa, necesit\\xe1s saber exactamente qu\\xe9 se logr\\xf3 y c\\xf3mo. No versiones embellecidas. Los n\\xfameros reales.\"\n        },\n        {\n            type: \"stat_grid\",\n            stats: [\n                {\n                    value: \"$174K\",\n                    label: \"Facturado en 6 meses\",\n                    sub: \"Desde Honduras, sin inversi\\xf3n externa\"\n                },\n                {\n                    value: \"$40K\",\n                    label: \"MRR al mes 6\",\n                    sub: \"Ingreso mensual recurrente\"\n                },\n                {\n                    value: \"$2K\",\n                    label: \"Primer cliente\",\n                    sub: \"Semana 3, primer cold email\"\n                },\n                {\n                    value: \"$200\",\n                    label: \"Inversi\\xf3n inicial\",\n                    sub: \"Solo LLC en Florida\"\n                }\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El timeline exacto\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Esto no pas\\xf3 de un d\\xeda para el otro. Pero tampoco tard\\xf3 a\\xf1os. Ac\\xe1 el desglose mes a mes:\"\n        },\n        {\n            type: \"timeline\",\n            steps: [\n                {\n                    step: \"Mes 1\",\n                    title: \"Estructura legal\",\n                    detail: \"LLC en Florida por menos de $200. Cuenta bancaria americana. Stripe configurado. Sin clientes, sin oferta clara todav\\xeda.\",\n                    time: \"Costo: $200 inversi\\xf3n\"\n                },\n                {\n                    step: \"Mes 2\",\n                    title: \"Primeros correos y primer cliente\",\n                    detail: \"Cre\\xe9 la oferta de servicios digitales. Mand\\xe9 500 cold emails. Los primeros 500 no generaron nada. Ajust\\xe9 el mensaje. En la semana 3, primer cliente: $2,000 USD.\",\n                    time: \"Primer ingreso: $2,000\"\n                },\n                {\n                    step: \"Mes 3\",\n                    title: \"Primer contratista en Filipinas\",\n                    detail: \"Contrat\\xe9 asistente en Filipinas a $5/hora para el fulfillment. Eso me liber\\xf3 tiempo para vender m\\xe1s. Volumen de outreach subi\\xf3 3x.\",\n                    time: \"MRR: ~$8,000\"\n                },\n                {\n                    step: \"Mes 4\",\n                    title: \"Sistema funcionando\",\n                    detail: \"$25,000 al mes. Ya no depend\\xeda de que yo cerrara cada cliente. El proceso era replicable. El sistema estaba probado.\",\n                    time: \"MRR: $25,000\"\n                },\n                {\n                    step: \"Mes 6\",\n                    title: \"Escala real\",\n                    detail: \"$40,000 mensuales recurrentes. Equipo remoto en Filipinas. 2-3 horas de trabajo al d\\xeda. Total acumulado en 6 meses: $174,000.\",\n                    time: \"MRR: $40,000\"\n                }\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"\\xbfPor qu\\xe9 te cuento esto?\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"No para impresionarte. Te lo cuento porque necesit\\xe1s entender algo fundamental: yo no soy especial. No ten\\xeda conexiones en USA. No hablaba ingl\\xe9s perfecto. No ten\\xeda experiencia previa en agencias digitales.\"\n        },\n        {\n            type: \"callout\",\n            variant: \"brand\",\n            content: \"La \\xfanica diferencia entre donde est\\xe1s hoy y donde llegu\\xe9 yo es una sola cosa: yo ejecut\\xe9. Tom\\xe9 el sistema, lo apliqu\\xe9 uno a uno, y no par\\xe9 cuando las cosas se pusieron dif\\xedciles. Eso es todo.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Lo que vas a aprender en este curso\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Este curso no es teor\\xeda. Es el sistema exacto que us\\xe9, documentado paso a paso. Al terminar vas a tener:\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"Un nicho definido con un cliente ideal claro y alcanzable\",\n                \"Una oferta que sea dif\\xedcil de rechazar con precio basado en valor\",\n                \"Una LLC formada en Florida, cuenta bancaria americana y Stripe configurado\",\n                \"Un sistema de cold email funcionando con 100+ emails/d\\xeda\",\n                \"Scripts de llamadas de ventas para cerrar clientes\",\n                \"Tu primer cliente pagando en d\\xf3lares\"\n            ]\n        },\n        {\n            type: \"warning\",\n            content: \"Este curso no es para todo el mundo. Si busc\\xe1s hacerte rico sin trabajar, cerr\\xe1 esto ahora. Si no est\\xe1s dispuesto a sentirte inc\\xf3modo, a que te rechacen, y a mandar 500 correos sin respuesta — esto no es para vos.\"\n        }\n    ],\n    \"leccion-1-2\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El ejercicio m\\xe1s importante antes de empezar\"\n        },\n        {\n            type: \"paragraph\",\n            content: 'Antes de aprender a conseguir clientes, necesitamos saber d\\xf3nde est\\xe1s parado. La diferencia entre \"quiero ganar m\\xe1s dinero\" y \"necesito generar $3,000 d\\xf3lares mensuales en los pr\\xf3ximos 90 d\\xedas para dejar mi trabajo\" es enorme. Una es un deseo vago. La otra es una misi\\xf3n.'\n        },\n        {\n            type: \"callout\",\n            variant: \"brand\",\n            content: \"Este curso solo funciona si ten\\xe9s una misi\\xf3n clara. No un sue\\xf1o. Una misi\\xf3n con n\\xfamero, con fecha, con raz\\xf3n.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Paso 1: Tu n\\xfamero real de libertad\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Libertad para m\\xed es poder llevar a mi hijo al parque un martes a las 10 de la ma\\xf1ana sin pedirle permiso a nadie. Es poder pagar las cuentas sin que el est\\xf3mago se apriete. Eso no requiere ser millonario. Requiere un sistema que genere ingresos predecibles en una moneda fuerte.\"\n        },\n        {\n            type: \"example\",\n            content: \"Ejemplo concreto de c\\xe1lculo de libertad:\\n\\nRenta: $400/mes\\nComida: $300/mes\\nServicios: $100/mes\\nTransporte: $150/mes\\nDeudas: $200/mes\\nMargen de respirar: $350/mes\\n─────────────────\\nTotal real: $1,500/mes\\n\\nEso son $1,500 USD. Para un negocio digital en USA, eso es 1-2 clientes medianos. No es un n\\xfamero imposible. Es tu punto de partida.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Paso 2: Inventario de realidad\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Las preguntas que nadie quiere hacerse pero que definen si esto funciona:\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"\\xbfTen\\xe9s una habilidad que alguien pagar\\xeda por usar? (dise\\xf1o, escritura, ventas, redes, automatizaci\\xf3n)\",\n                \"\\xbfTen\\xe9s computadora y acceso a internet estable?\",\n                \"\\xbfTen\\xe9s 2-3 horas al d\\xeda que puedas proteger como si tu futuro dependiera de ellas?\",\n                \"\\xbfTen\\xe9s $200-500 USD para invertir en tu empresa?\",\n                \"\\xbfEst\\xe1s dispuesto a hacer cosas inc\\xf3modas por 90 d\\xedas seguidos?\"\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"info\",\n            content: \"Si no ten\\xe9s habilidad vendible todav\\xeda: las m\\xe1s r\\xe1pidas de aprender en 2-3 semanas son manejo de redes sociales, dise\\xf1o b\\xe1sico con Canva, configuraci\\xf3n de automatizaciones con IA, y cold email outreach.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Paso 3: Tu meta de 90 d\\xedas\"\n        },\n        {\n            type: \"comparison\",\n            sides: {\n                left: {\n                    title: \"Arrancando de cero (sin experiencia)\",\n                    items: [\n                        \"Meta: $1,000 - $3,000 en 90 d\\xedas\",\n                        \"Enfoque: conseguir el primer cliente\",\n                        \"No mensual — total en 90 d\\xedas\",\n                        \"Ese primer cliente cambia todo\"\n                    ]\n                },\n                right: {\n                    title: \"Con experiencia o habilidad previa\",\n                    items: [\n                        \"Meta: $3,000 - $10,000 en 90 d\\xedas\",\n                        \"Enfoque: primeros 2-3 clientes\",\n                        \"Puede aspirar a recurrente\",\n                        \"Precio m\\xe1s alto desde el inicio\"\n                    ]\n                }\n            }\n        },\n        {\n            type: \"warning\",\n            content: \"Hay un momento en los pr\\xf3ximos 90 d\\xedas donde vas a querer dejarlo. Donde vas a mandar correos y nadie va a responder. En ese momento, volv\\xe9 a lo que escribiste hoy. Tu definici\\xf3n de libertad. Tu n\\xfamero. Tu raz\\xf3n. El sistema funciona. Pero solo si no par\\xe1s.\"\n        }\n    ],\n    \"leccion-1-3\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"\\xbfPor qu\\xe9 no vender solo en tu pa\\xeds?\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Esta es la pregunta que mucha gente se hace y nunca dice en voz alta. La respuesta es matem\\xe1tica, no moral.\"\n        },\n        {\n            type: \"number_breakdown\",\n            numbers: [\n                {\n                    num: \"25:1\",\n                    label: \"Tasa de cambio Honduras\",\n                    detail: \"$2,000 USD = m\\xe1s de 50,000 lempiras. Para ganar lo mismo con clientes locales, necesitar\\xedas cobrar 50,000 lempiras por proyecto.\"\n                },\n                {\n                    num: \"18:1\",\n                    label: \"Tasa de cambio Colombia\",\n                    detail: \"$2,000 USD = ~8,000,000 COP. \\xbfCu\\xe1ntos negocios colombianos pagan eso por un servicio digital?\"\n                },\n                {\n                    num: \"17:1\",\n                    label: \"Tasa de cambio M\\xe9xico\",\n                    detail: \"$2,000 USD = ~35,000 MXN. Posible, pero el mercado es mucho m\\xe1s competitivo y los precios m\\xe1s bajos.\"\n                }\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El mercado americano en n\\xfameros\"\n        },\n        {\n            type: \"stat_grid\",\n            stats: [\n                {\n                    value: \"33M+\",\n                    label: \"Peque\\xf1as empresas en USA\",\n                    sub: \"Cada una necesita servicios digitales\"\n                },\n                {\n                    value: \"5M+\",\n                    label: \"Empresas de due\\xf1os hispanos\",\n                    sub: \"Prefieren trabajar con alguien que habla espa\\xf1ol\"\n                },\n                {\n                    value: \"$1,500\",\n                    label: \"Precio promedio/mes aceptable\",\n                    sub: \"Para un negocio americano, es un gasto normal\"\n                },\n                {\n                    value: \"0\",\n                    label: \"D\\xf3lares en publicidad pagada\",\n                    sub: \"Para conseguir tus primeros clientes con cold email\"\n                }\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Matando las excusas una por una\"\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: '❌ Excusa #1: \"No tengo experiencia\"\\n\\nLa experiencia no se consigue estudiando. Se consigue ejecutando. Tu primer cliente no te va a contratar por tu curr\\xedculum. Te va a contratar porque le presentaste una soluci\\xf3n clara a un problema real.\\n\\nHay gente en USA cobrando $5,000/mes por hacer cosas que pod\\xe9s aprender en dos semanas. No porque sean genios. Porque se atrevieron a ofrecer el servicio.'\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: '❌ Excusa #2: \"No s\\xe9 ingl\\xe9s\"\\n\\nPrimero: hay 5M+ de negocios hispanos en USA que prefieren trabajar con alguien que habla su idioma.\\n\\nSegundo: las herramientas de IA hoy te permiten escribir correos en ingl\\xe9s perfecto en segundos.\\n\\nTercero: lo que importa es resolver problemas y cumplir lo que promet\\xe9s. Eso paga las cuentas, no tu acento.'\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: '❌ Excusa #3: \"No tengo dinero para empezar\"\\n\\nLLC: menos de $200. Herramientas b\\xe1sicas: $30-50/mes. Sin oficina. Sin inventario. Sin empleados al inicio.\\n\\nCompar\\xe1 eso con abrir cualquier negocio f\\xedsico: local, inventario, empleados, permisos = miles de d\\xf3lares antes de generar un centavo.\\n\\nUn negocio digital de servicios es el modelo con menor barrera de entrada que existe.'\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: '❌ Excusa #4: \"No es el momento adecuado\"\\n\\n\\xbfSab\\xe9s cu\\xe1ndo va a ser el momento perfecto? Nunca. Siempre va a haber algo. Siempre va a haber una raz\\xf3n para esperar.\\n\\nLa gente que construye cosas no espera a que las condiciones sean ideales. Construye con lo que tiene, donde est\\xe1, ahora.'\n        },\n        {\n            type: \"quote\",\n            content: \"Lo dif\\xedcil es el filtro. Las excusas son el filtro. La incomodidad es el filtro. Y vos est\\xe1s aqu\\xed porque decidiste pasar ese filtro.\",\n            author: \"Jose Angel\"\n        }\n    ]\n};\n// ─────────────────────────────────────────────\n// MÓDULO 2 — ELIGE TU NICHO\n// ─────────────────────────────────────────────\nconst MODULE_2_CONTENT = {\n    \"leccion-2-1\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El problema que nadie te dice\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Si est\\xe1s mandando mensajes y nadie responde, si public\\xe1s contenido y nadie compra — el problema probablemente no es lo que vend\\xe9s. El problema es a qui\\xe9n se lo est\\xe1s vendiendo.\"\n        },\n        {\n            type: \"comparison\",\n            sides: {\n                left: {\n                    title: \"❌ Mensaje gen\\xe9rico (nadie responde)\",\n                    items: [\n                        '\"Hago logos profesionales para tu negocio\"',\n                        '\"Precios accesibles. Resultados garantizados.\"',\n                        \"Le est\\xe1s hablando a todo el mundo\",\n                        \"Cuando le habl\\xe1s a todos, no le habl\\xe1s a nadie\"\n                    ]\n                },\n                right: {\n                    title: \"✅ Mensaje espec\\xedfico (genera respuestas)\",\n                    items: [\n                        '\"Ayudo a restaurantes nuevos en Miami a tener logo y men\\xfa profesional en 72 horas\"',\n                        '\"Para que puedan abrir sin retrasos\"',\n                        \"Una persona espec\\xedfica con un problema urgente\",\n                        \"Eso genera respuestas\"\n                    ]\n                }\n            }\n        },\n        {\n            type: \"paragraph\",\n            content: \"Mismo servicio. Misma habilidad. Pero el segundo tiene un cliente espec\\xedfico, un problema espec\\xedfico y un resultado concreto. Eso es lo que genera respuestas.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El orden correcto que casi nadie sigue\"\n        },\n        {\n            type: \"timeline\",\n            steps: [\n                {\n                    step: \"Primero\",\n                    title: \"Identificar qui\\xe9n tiene un problema real y urgente\",\n                    detail: 'No \"empresas en general\". Una persona espec\\xedfica con un dolor que le quita el sue\\xf1o y dinero para resolverlo.'\n                },\n                {\n                    step: \"Segundo\",\n                    title: \"Entender ese problema profundamente\",\n                    detail: \"Qu\\xe9 lo causa, qu\\xe9 lo agrava, qu\\xe9 ha intentado antes y por qu\\xe9 no funcion\\xf3.\"\n                },\n                {\n                    step: \"Tercero\",\n                    title: \"Adaptar lo que sab\\xe9s hacer para resolver ese problema\",\n                    detail: \"Tu habilidad se moldea al dolor. No al rev\\xe9s.\"\n                }\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"brand\",\n            content: \"La mayor\\xeda piensa en lo que saben hacer y despu\\xe9s busca a qui\\xe9n vend\\xe9rselo. Es al rev\\xe9s. Primero encontr\\xe1s el problema, despu\\xe9s adapt\\xe1s la soluci\\xf3n.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Se\\xf1ales de que tu targeting est\\xe1 mal\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"Mand\\xe1s mensajes y te dejan en visto (mensaje lleg\\xf3 a alguien sin ese problema)\",\n                'Te dicen \"interesante\" o \"d\\xe9jame pensarlo\" pero nunca compran (no hay urgencia)',\n                \"Baj\\xe1s tus precios pensando que es un tema de costo (casi nunca lo es)\",\n                'Cambi\\xe1s tu oferta cada dos semanas porque \"no funciona\" (mat\\xe1s una oferta buena antes de tiempo)'\n            ]\n        }\n    ],\n    \"leccion-2-3\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Los 5 filtros para elegir a qui\\xe9n le vas a vender\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"No toda persona con un problema es un buen cliente. Estos 5 filtros te ahorran semanas de mandar mensajes a las personas equivocadas.\"\n        },\n        {\n            type: \"number_breakdown\",\n            numbers: [\n                {\n                    num: \"1\",\n                    label: \"Dolor activo\",\n                    detail: 'Esta persona siente el dolor HOY, no lo sabe te\\xf3ricamente. El due\\xf1o del restaurante que VE las mesas vac\\xedas cada noche. No alguien que \"deber\\xeda\" mejorar su marketing.'\n                },\n                {\n                    num: \"2\",\n                    label: \"Urgencia\",\n                    detail: '\\xbfNecesita resolverlo ahora o \"alg\\xfan d\\xeda\"? Busc\\xe1 se\\xf1ales: acaban de abrir, se acerca temporada fuerte, est\\xe1n perdiendo dinero cada mes, el contador les dijo que las cosas no van bien.'\n                },\n                {\n                    num: \"3\",\n                    label: \"Capacidad de pago\",\n                    detail: \"Un negocio que factura $30K/mes puede pagarte $1,500 sin pesta\\xf1ear si le resolv\\xe9s un problema real. Vendele a quien ya invierte en soluciones, no a quien nunca ha pagado por un servicio.\"\n                },\n                {\n                    num: \"4\",\n                    label: \"Autoridad\",\n                    detail: 'La persona a quien le habl\\xe1s, \\xbfpuede decir \"s\\xed\" y pagarte? \\xbfO tiene que pedirle permiso a alguien? Habl\\xe1 con el due\\xf1o, el fundador, quien firma los cheques. No el gerente.'\n                },\n                {\n                    num: \"5\",\n                    label: \"Comunidad\",\n                    detail: \"\\xbfPod\\xe9s encontrar a esta gente? \\xbfEst\\xe1n en LinkedIn, Google Maps, Instagram, grupos de Facebook, directorios? Si no pod\\xe9s encontrarlos, no importa qu\\xe9 tan perfecto sea tu ICP.\"\n                }\n            ]\n        },\n        {\n            type: \"example\",\n            content: \"Ejercicio de puntuaci\\xf3n:\\n\\nCalific\\xe1 tu ICP del 1 al 5 en cada filtro:\\n\\nRestaurantes hispanos en Miami:\\n• Dolor: 5/5 (mesas vac\\xedas = p\\xe9rdida real cada d\\xeda)\\n• Urgencia: 4/5 (cada semana sin clientes es dinero perdido)\\n• Capacidad de pago: 4/5 (facturan $20K-80K/mes)\\n• Autoridad: 5/5 (el due\\xf1o decide solo)\\n• Comunidad: 5/5 (Google Maps, Instagram, grupos FB)\\n\\nPuntaje total: 23/25 → Excelente candidato\"\n        },\n        {\n            type: \"callout\",\n            variant: \"info\",\n            content: \"El filtro m\\xe1s olvidado es el de Comunidad. Pod\\xe9s tener el cliente ideal perfecto en tu cabeza pero si no sab\\xe9s d\\xf3nde encontrarlo, no te sirve de nada. Antes de comprometerte con un nicho, buscalo en Google Maps, LinkedIn, e Instagram. Si encontr\\xe1s decenas de resultados en 10 minutos, est\\xe1s bien.\"\n        }\n    ],\n    \"leccion-2-4\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El tri\\xe1ngulo que define si tu negocio tiene futuro\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Pod\\xe9s encontrar gente con dolor y dinero, pero si no pod\\xe9s resolver su problema o demostrarlo, no hay negocio. Las tres esquinas tienen que estar presentes.\"\n        },\n        {\n            type: \"stat_grid\",\n            stats: [\n                {\n                    value: \"\\uD83D\\uDCA1\",\n                    label: \"Habilidad\",\n                    sub: \"Lo que sab\\xe9s hacer que tiene valor real\"\n                },\n                {\n                    value: \"\\uD83D\\uDCCB\",\n                    label: \"Prueba\",\n                    sub: \"Lo que pod\\xe9s demostrar (no solo decir)\"\n                },\n                {\n                    value: \"\\uD83D\\uDCB0\",\n                    label: \"Demanda\",\n                    sub: \"Lo que la gente ya paga por resolver\"\n                }\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 3,\n            content: \"\\xbfQu\\xe9 pasa cuando falta una esquina?\"\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: '⚠️ Habilidad + Demanda sin Prueba: Consegu\\xeds atenci\\xf3n pero no confianza. La gente dice \"suena bien\" y desaparece. SOLUCI\\xd3N: consegu\\xed tu primer cliente a como d\\xe9 lugar, aunque sea barato. Us\\xe1 ese resultado como prueba.'\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: \"⚠️ Habilidad + Prueba sin Demanda: Sos bueno, ten\\xe9s resultados, pero vend\\xe9s algo que nadie necesita con urgencia. SOLUCI\\xd3N: cambi\\xe1 de mercado o reposicion\\xe1 hacia un dolor que s\\xed sea urgente.\"\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: \"⚠️ Demanda + Prueba sin Habilidad: Vas a vender pero no vas a poder entregar. SOLUCI\\xd3N: o aprend\\xe9s la habilidad r\\xe1pido, o contrat\\xe1s a alguien que la tenga. As\\xed funcionan las agencias.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Habilidades vendibles que pod\\xe9s aprender en 2-3 semanas\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"Manejo de redes sociales (Instagram, Facebook, LinkedIn para negocios)\",\n                \"Dise\\xf1o b\\xe1sico con Canva o Figma (logos, posts, men\\xfas)\",\n                \"Cold email outreach y configuraci\\xf3n de secuencias\",\n                \"Configuraci\\xf3n de CRMs (HubSpot, GoHighLevel)\",\n                \"Automatizaciones b\\xe1sicas con Make.com o Zapier\",\n                \"Gesti\\xf3n de Google My Business y reputaci\\xf3n online\",\n                \"Edici\\xf3n de video corto para Reels e historias\",\n                \"Configuraci\\xf3n de anuncios Facebook/Instagram b\\xe1sicos\"\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"info\",\n            content: \"\\xbfNo ten\\xe9s prueba todav\\xeda? Eso es completamente normal. Opciones para construirla r\\xe1pido:\\n\\n1. Hacer un proyecto personal y documentarlo (cre\\xe1 una cuenta de Instagram para un negocio ficticio y mostr\\xe1 el crecimiento)\\n2. Ofrecerle a un amigo o familiar hacer el trabajo gratis o muy barato a cambio de un testimonial\\n3. Tu primer cliente real ES tu prueba — cobr\\xe1 menos, entreg\\xe1 m\\xe1s, y us\\xe1 ese resultado para los pr\\xf3ximos\"\n        }\n    ]\n};\n// ─────────────────────────────────────────────\n// MÓDULO 3 — DISEÑA TU OFERTA\n// ─────────────────────────────────────────────\nconst MODULE_3_CONTENT = {\n    \"leccion-3-2\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Los 4 pilares de una oferta irresistible\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Cada vez que alguien ve tu oferta, su cerebro hace un c\\xe1lculo autom\\xe1tico basado en 4 factores. Tu trabajo es maximizar los primeros dos y minimizar los \\xfaltimos dos.\"\n        },\n        {\n            type: \"number_breakdown\",\n            numbers: [\n                {\n                    num: \"↑\",\n                    label: \"Resultado grande (maximizar)\",\n                    detail: '\"Mesas llenas de lunes a jueves\" > \"Manejo de redes sociales\". El resultado tiene que ser espec\\xedfico, deseable y cre\\xedble. No exagerado. Grande pero real.'\n                },\n                {\n                    num: \"↑\",\n                    label: \"Probabilidad alta (maximizar)\",\n                    detail: \"Si no ten\\xe9s testimoniales, us\\xe1 claridad. Explic\\xe1 tu proceso paso a paso. Mencion\\xe1 el dolor con sus mismas palabras. Eso genera confianza antes de tener prueba.\"\n                },\n                {\n                    num: \"↓\",\n                    label: \"Tiempo corto (minimizar)\",\n                    detail: 'Estructur\\xe1 tu oferta para que haya un \"quick win\" en la primera semana. Aunque el resultado completo tarde 60 d\\xedas, el cliente necesita ver algo funcionando r\\xe1pido.'\n                },\n                {\n                    num: \"↓\",\n                    label: \"Esfuerzo del cliente (minimizar)\",\n                    detail: '\"Yo me encargo de todo, vos solo me das acceso\" > \"Te voy a ense\\xf1ar a hacer esto\". Entre menos esfuerzo le ped\\xeds, m\\xe1s f\\xe1cil es que diga que s\\xed.'\n                }\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"La f\\xf3rmula de tu frase de oferta\"\n        },\n        {\n            type: \"callout\",\n            variant: \"brand\",\n            content: '\"Yo ayudo a [cliente espec\\xedfico] a lograr [resultado concreto] sin [obst\\xe1culo o dolor que quieren evitar].\"'\n        },\n        {\n            type: \"example\",\n            content: 'Ejemplos reales por nicho:\\n\\n\\uD83C\\uDF7D️ Restaurantes:\\n\"Ayudo a restaurantes hispanos en USA a llenar mesas entre semana sin depender del boca a boca ni gastar en publicidad que no funciona.\"\\n\\n\\uD83E\\uDDB7 Dentistas:\\n\"Ayudo a dentistas nuevos a conseguir 20+ pacientes al mes sin contratar un equipo de marketing ni gastar miles en agencias.\"\\n\\n\\uD83D\\uDCAA Coaches de fitness:\\n\"Ayudo a coaches de fitness online a llenar sus programas con clientes que pagan premium sin vivir pegados a Instagram 8 horas al d\\xeda.\"\\n\\n\\uD83C\\uDFE0 Agentes de bienes ra\\xedces:\\n\"Ayudo a agentes hispanos en USA a generar 5-8 citas de compradores por mes sin hacer llamadas en fr\\xedo ni gastar en leads.\"'\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Value stacking: c\\xf3mo hacer que $1,500 se sienta como $5,000\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"El value stacking es apilar valor percibido alrededor de tu servicio principal. No relleno. Cosas que le cuestan poco a vos pero que el cliente percibe como muy valioso.\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"Reporte mensual de resultados (te toma 2 horas, el cliente lo percibe como premium)\",\n                \"Acceso directo por WhatsApp para preguntas r\\xe1pidas (sin costo, genera mucha confianza)\",\n                \"Setup de herramientas incluido (lo hac\\xe9s una vez, parece un servicio extra)\",\n                \"Template o checklist personalizado para su industria\",\n                \"Auditor\\xeda inicial gratuita de su situaci\\xf3n actual\",\n                'Garant\\xeda de resultados: \"Si en 30 d\\xedas no ves avance, trabajo gratis hasta que lo veas\"'\n            ]\n        }\n    ],\n    \"leccion-3-3\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Por qu\\xe9 cobrar barato es peor que cobrar caro\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Parece al rev\\xe9s. Uno pensar\\xeda que si cobr\\xe1s barato, m\\xe1s gente te compra y es m\\xe1s f\\xe1cil vender. Mentira. Es lo contrario.\"\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: \"\\uD83D\\uDD34 Cobrar barato atrae malos clientes. Los que buscan lo m\\xe1s barato son los m\\xe1s dif\\xedciles: piden m\\xe1s, se quejan m\\xe1s, pagan tarde, cuestionan todo. Los mejores clientes que tuve fueron los que pagaban premium.\"\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: \"\\uD83D\\uDD34 Cobrar barato destruye tu capacidad de entregar. Si cobr\\xe1s $300 en vez de $1,500, necesit\\xe1s 5 clientes para ganar lo mismo que con uno. Eso son 5 proyectos, 5 personas, 5 veces m\\xe1s trabajo. La calidad baja. Los clientes se van.\"\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: \"\\uD83D\\uDD34 Cobrar barato le dice al mercado que no val\\xe9s mucho. Cuando alguien ve dos opciones — una de $500 y una de $2,000 — asume que la de $2,000 es mejor. El precio mismo es la se\\xf1al.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Pricing basado en valor — el \\xfanico que funciona\"\n        },\n        {\n            type: \"example\",\n            content: \"C\\xf3mo calcular tu precio:\\n\\n1. \\xbfCu\\xe1nto vale el resultado para tu cliente?\\n   → Si tu servicio le genera 20 clientes nuevos/mes a un restaurante\\n   → Cada cliente gasta $60 en promedio\\n   → Eso son $1,200 de ingreso adicional mensual\\n   → Al a\\xf1o: $14,400\\n\\n2. \\xbfCu\\xe1nto deber\\xedas cobrar?\\n   → $1,500/mes es el 10% del valor que gener\\xe1s\\n   → Para el cliente: cada mes paga $1,500 y recibe $1,200 de valor\\n   → En 2 meses recuper\\xf3 la inversi\\xf3n\\n\\nTu precio no es lo que te sent\\xeds c\\xf3modo cobrando.\\nTu precio es lo que vale el resultado que promet\\xe9s.\"\n        },\n        {\n            type: \"stat_grid\",\n            stats: [\n                {\n                    value: \"$500-1K\",\n                    label: \"Precio de lanzamiento\",\n                    sub: \"Sin clientes ni portafolio. Solo para conseguir prueba.\"\n                },\n                {\n                    value: \"$1.5-2.5K\",\n                    label: \"Precio est\\xe1ndar\",\n                    sub: \"Con 1-2 clientes y resultados demostrables.\"\n                },\n                {\n                    value: \"$2.5-5K\",\n                    label: \"Precio senior\",\n                    sub: \"Con 3-5 clientes, testimoniales y proceso probado.\"\n                }\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"brand\",\n            content: \"Regla de oro: si nunca nadie te dice que es caro, est\\xe1s cobrando muy poco. Los buenos clientes negocian pero pagan. Los malos clientes regatean y despu\\xe9s son un dolor de cabeza.\"\n        }\n    ]\n};\n// ─────────────────────────────────────────────\n// MÓDULO 4 — INCORPORACIÓN EN USA\n// ─────────────────────────────────────────────\nconst MODULE_4_CONTENT = {\n    \"leccion-4-2\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"C\\xf3mo formar tu LLC en Florida paso a paso\"\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: \"⚠️ Disclaimer: No soy abogado ni contador. Esto es mi experiencia personal y lo que he visto funcionar. Para decisiones espec\\xedficas sobre tu situaci\\xf3n, consult\\xe1 con un profesional.\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"La plataforma que recomiendo es Doola. Est\\xe1 dise\\xf1ada espec\\xedficamente para personas que no viven en USA: no necesit\\xe1s SSN, no necesit\\xe1s direcci\\xf3n americana, no necesit\\xe1s visa.\"\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"Doola\",\n                url: \"https://doola.com\",\n                price: \"$300-500 pago \\xfanico (incluye LLC + EIN)\",\n                why: \"Dise\\xf1ado para no residentes de USA. Te da LLC, EIN, direcci\\xf3n registrada y documentos listos para banco y Stripe. C\\xf3digo de descuento: REFERAFOUNDER10 (10% off)\",\n                icon: \"\\uD83C\\uDFDB️\"\n            }\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"\\xbfPor qu\\xe9 Florida?\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"Sin impuesto estatal sobre ingresos (0% state income tax)\",\n                \"Filing fee de los m\\xe1s bajos del pa\\xeds ($125)\",\n                \"Estado amigable para negocios y startups\",\n                \"Comunidad hispana enorme — \\xfatil para networking\",\n                \"Muchos servicios bancarios y legales est\\xe1n familiarizados con no residentes\"\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Lo que necesit\\xe1s antes de empezar\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"Pasaporte vigente (foto clara, sin vencer)\",\n                \"Email que revis\\xe1s todos los d\\xedas\",\n                \"Nombre de tu empresa decidido (pod\\xe9s cambiarlo despu\\xe9s)\",\n                \"Recibo p\\xfablico a tu nombre (agua, luz, tel\\xe9fono) — MUY IMPORTANTE para verificaci\\xf3n\",\n                \"$300-500 para el pago\",\n                \"NO agregar socios — hacelo solo para simplificar la apertura bancaria\"\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"warning\",\n            content: \"⚠️ CR\\xcdTICO sobre el recibo p\\xfablico: Asegurate de tener un recibo de servicios p\\xfablicos con tu nombre y direcci\\xf3n. Si todo est\\xe1 a nombre de otra persona (c\\xf3nyuge, familiar), la LLC tendr\\xe1 que ir a nombre de esa persona. Esto caus\\xf3 muchos dolores de cabeza a quienes no lo supieron de antemano.\"\n        },\n        {\n            type: \"timeline\",\n            steps: [\n                {\n                    step: \"D\\xeda 1\",\n                    title: \"Completar formulario en Doola\",\n                    detail: 'And\\xe1 a doola.com, hac\\xe9 clic en \"Start a U.S. Company\", seleccion\\xe1 LLC, eleg\\xed Florida, complet\\xe1 tus datos y pag\\xe1.'\n                },\n                {\n                    step: \"D\\xedas 1-14\",\n                    title: \"Esperar documentos\",\n                    detail: \"Doola procesa tu solicitud. Recibir\\xe1s por email: Articles of Organization, EIN (carta del IRS), Operating Agreement, y direcci\\xf3n registrada.\"\n                },\n                {\n                    step: \"D\\xeda 14-15\",\n                    title: \"Aplicar al banco\",\n                    detail: \"Con los documentos en mano, aplic\\xe1s a Mercury o Relay. El proceso es 100% online, toma 15-20 minutos.\"\n                },\n                {\n                    step: \"D\\xeda 16-20\",\n                    title: \"Cuenta bancaria activa\",\n                    detail: \"Banco aprobado. Configur\\xe1s Stripe. Hac\\xe9s un pago de prueba de $1 para verificar que todo funciona.\"\n                },\n                {\n                    step: \"D\\xeda 21+\",\n                    title: \"Listo para cobrar\",\n                    detail: \"Tu empresa existe legalmente en USA, pod\\xe9s facturar a clientes americanos, recibir pagos y mover dinero a tu pa\\xeds.\"\n                }\n            ]\n        }\n    ],\n    \"leccion-4-4\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Apertura de cuenta bancaria americana — gu\\xeda completa\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Ten\\xe9s tres opciones principales. Las tres funcionan para no residentes. Las tres son 100% digitales.\"\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"Mercury (Recomendado principal)\",\n                url: \"https://mercury.com\",\n                price: \"Gratis — sin fees ni m\\xednimos\",\n                why: \"Banco digital dise\\xf1ado para empresas y fundadores. Interfaz limpia, se conecta perfecto con Stripe, dashboard profesional. Mi banco principal desde el primer d\\xeda.\",\n                icon: \"\\uD83C\\uDFE6\"\n            }\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"Relay (Plan B)\",\n                url: \"https://relayfi.com\",\n                price: \"Gratis — plan b\\xe1sico sin fees\",\n                why: \"Proceso de aprobaci\\xf3n m\\xe1s flexible para no residentes. Permite crear m\\xfaltiples cuentas (ingresos, gastos, impuestos). Ideal si Mercury rechaza.\",\n                icon: \"\\uD83C\\uDFE6\"\n            }\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"Wise (Para mover dinero)\",\n                url: \"https://wise.com\",\n                price: \"0.5-1.5% por transferencia (mucho menor que bancos)\",\n                why: \"No reemplaza al banco principal. Es el puente entre tu cuenta americana y tu banco local. Las mejores tasas de cambio del mercado.\",\n                icon: \"\\uD83D\\uDCB1\"\n            }\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Consejos para que te aprueben a la primera\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"Nombre de la LLC exactamente igual en todos los documentos (copia y pega, nunca escribas a mano)\",\n                \"Usar la direcci\\xf3n que te dio Doola — no inventar una\",\n                \"Tener presencia online antes de aplicar (LinkedIn, p\\xe1gina simple, Instagram de negocio)\",\n                'Descripci\\xf3n espec\\xedfica del negocio: \"We provide digital marketing services to small businesses in the United States\" — nunca solo \"consulting\"',\n                \"Tener todos los documentos abiertos antes de empezar (pasaporte escaneado, EIN, Articles of Organization)\",\n                'El nombre en el banco debe coincidir exactamente con el de tu LLC incluyendo \"LLC\"'\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"info\",\n            content: \"\\xbfTe rechazaron? Revis\\xe1 estas causas m\\xe1s comunes:\\n\\n1. El nombre de la LLC no coincide exactamente\\n2. No encontraron tu empresa online (crean tu presencia antes)\\n3. Descripci\\xf3n del negocio demasiado vaga\\n4. Documentos borrosos o incompletos\\n\\nCorreg\\xed y volv\\xe9 a aplicar. La mayor\\xeda se aprueba en el segundo intento.\"\n        }\n    ],\n    \"leccion-4-5\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Configurar Stripe — paso a paso\"\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"Stripe\",\n                url: \"https://stripe.com\",\n                price: \"2.9% + $0.30 por transacci\\xf3n (sin fee mensual)\",\n                why: \"El est\\xe1ndar de pagos para negocios B2B en USA. Los clientes americanos conf\\xedan en Stripe. Se integra con todo. Tus clientes pagan con tarjeta y el dinero llega a Mercury en 2-3 d\\xedas.\",\n                icon: \"\\uD83D\\uDCB3\"\n            }\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El flujo completo del dinero\"\n        },\n        {\n            type: \"timeline\",\n            steps: [\n                {\n                    step: \"1\",\n                    title: \"Cliente paga\",\n                    detail: \"Tu cliente recibe tu link de Stripe, pone su tarjeta de cr\\xe9dito o d\\xe9bito, y paga en segundos. Puede estar en cualquier parte de USA.\"\n                },\n                {\n                    step: \"2\",\n                    title: \"Stripe procesa\",\n                    detail: \"Stripe retiene el 2.9% + $0.30 de comisi\\xf3n y deposita el resto en tu cuenta de Mercury en 2-3 d\\xedas h\\xe1biles.\"\n                },\n                {\n                    step: \"3\",\n                    title: \"Mercury lo recibe\",\n                    detail: \"El dinero aterriza en tu cuenta business americana. Ac\\xe1 es donde se queda para operar tu negocio.\"\n                },\n                {\n                    step: \"4\",\n                    title: \"Wise transfiere\",\n                    detail: 'En fechas fijas (ej: el 1 y 15 de cada mes), transfer\\xeds tu \"salario\" de Mercury a tu cuenta local via Wise. Las mejores tasas de cambio del mercado.'\n                },\n                {\n                    step: \"5\",\n                    title: \"Tu banco local\",\n                    detail: \"El dinero llega en tu moneda local en 1-3 d\\xedas h\\xe1biles. Sin pasar por cambistas informales, 100% legal y trazable.\"\n                }\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"brand\",\n            content: \"Regla de oro: desde el d\\xeda uno, todo el dinero del negocio pasa por tu cuenta de negocio. Tu cuenta personal es para tu vida personal. Nunca las mezcles — pierdes la protecci\\xf3n legal de tu LLC.\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: 'Tu sistema de \"salario\"'\n        },\n        {\n            type: \"example\",\n            content: 'Framework para manejar tu dinero:\\n\\n\\uD83D\\uDCE5 TODO lo que entra → cuenta Mercury\\n\\n\\uD83D\\uDCB0 Tu \"salario\" fijo → transfer\\xeds el mismo monto el 1 y 15 de cada mes via Wise\\n   → Ej: $800/mes para vivir en Honduras\\n\\n\\uD83D\\uDD27 Colch\\xf3n operativo → dej\\xe1s siempre 1-2 meses de gastos en Mercury\\n   → Ej: si gastas $300/mes en herramientas, dej\\xe1s $600 siempre\\n\\n\\uD83D\\uDCCA El resto → queda en Mercury para crecer o invertir en el negocio\\n\\nTratalo como una n\\xf3mina. Vos sos el empleado de tu empresa. Tu empresa te paga en fechas fijas.'\n        }\n    ]\n};\n// ─────────────────────────────────────────────\n// MÓDULO 5 — PRIMEROS CLIENTES\n// ─────────────────────────────────────────────\nconst MODULE_5_CONTENT = {\n    \"leccion-5-2\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Por qu\\xe9 tu email cae en spam (y c\\xf3mo evitarlo)\"\n        },\n        {\n            type: \"paragraph\",\n            content: \"Antes de escribir un solo email, necesit\\xe1s entender c\\xf3mo funcionan los filtros de spam. Si los ignor\\xe1s, todo tu trabajo va a ser invisible.\"\n        },\n        {\n            type: \"callout\",\n            variant: \"info\",\n            content: \"Los filtros eval\\xfaan 3 cosas:\\n\\n1. \\xbfQui\\xe9n manda este email? \\xbfDominio nuevo sin historial, o cuenta establecida?\\n2. \\xbfEst\\xe1 bien configurado? \\xbfTiene SPF, DKIM y DMARC?\\n3. \\xbfC\\xf3mo se comporta? \\xbfManda 500 emails el primer d\\xeda como robot, o gradualmente como persona real?\"\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"Instantly.ai\",\n                url: \"https://instantly.ai\",\n                price: \"$30-97/mes seg\\xfan plan\",\n                why: \"Todo en uno: comprar dominios, crear emails, hacer warmup autom\\xe1tico, y lanzar campa\\xf1as. Evita tener que usar 4 herramientas distintas. Es lo que uso para todo mi outreach.\",\n                icon: \"\\uD83D\\uDCE7\"\n            }\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Setup paso a paso\"\n        },\n        {\n            type: \"timeline\",\n            steps: [\n                {\n                    step: \"Paso 1\",\n                    title: \"Comprar dominios secundarios\",\n                    detail: \"NUNCA uses tu dominio principal para cold email. Compr\\xe1 3-5 dominios secundarios (ej: si ten\\xe9s freedomai.com, compr\\xe1 getfreedomai.com, tryfreedomai.com, meetfreedomai.com). Cuesta ~$10-15 cada uno.\"\n                },\n                {\n                    step: \"Paso 2\",\n                    title: \"Crear cuentas de email\",\n                    detail: \"Por cada dominio, cre\\xe1 1-2 cuentas con nombres reales: jose@getfreedomai.com, maria@tryfreedomai.com. NUNCA info@, sales@, o contact@ — los filtros los detectan.\"\n                },\n                {\n                    step: \"Paso 3\",\n                    title: \"Verificar autenticaci\\xf3n\",\n                    detail: \"Verific\\xe1 que SPF, DKIM y DMARC est\\xe9n en VERDE en Instantly. Sin esto, vas directo a spam aunque tu mensaje sea perfecto. Instantly los configura autom\\xe1ticamente.\"\n                },\n                {\n                    step: \"Paso 4\",\n                    title: \"Activar warmup\",\n                    detail: \"Instantly simula conversaciones reales entre tus cuentas. Empez\\xe1 con 10-20 emails/d\\xeda e increment\\xe1 gradualmente. Dur\\xe1 M\\xcdNIMO 2 semanas antes de mandar campa\\xf1as.\"\n                }\n            ]\n        },\n        {\n            type: \"warning\",\n            content: \"Las 2 semanas de warmup son innegociables. S\\xe9 que quer\\xe9s empezar ya. Pero si mand\\xe1s emails desde cuentas fr\\xedas, quem\\xe1s los dominios y empez\\xe1s de cero. 2 semanas de preparaci\\xf3n = meses de campa\\xf1as funcionando.\"\n        }\n    ],\n    \"leccion-5-3\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"C\\xf3mo construir tu lista de prospectos\"\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"Apollo.io\",\n                url: \"https://apollo.io\",\n                price: \"Plan gratuito disponible / Pagos desde $49/mes\",\n                why: \"Base de datos con millones de contactos de negocios. Filtr\\xe1s por industria, cargo, ubicaci\\xf3n, tama\\xf1o de empresa y obten\\xe9s el email verificado de decisores reales.\",\n                icon: \"\\uD83D\\uDD0D\"\n            }\n        },\n        {\n            type: \"tool_card\",\n            tool: {\n                name: \"MillionVerifier\",\n                url: \"https://millionverifier.com\",\n                price: \"~$10 por cada 10,000 emails verificados\",\n                why: \"Verifica si cada email de tu lista existe y est\\xe1 activo. Sin esto, tu tasa de rebote sube y quem\\xe1s los dominios. Es el paso que m\\xe1s gente se salta y despu\\xe9s se arrepiente.\",\n                icon: \"✅\"\n            }\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"El proceso de construcci\\xf3n de lista\"\n        },\n        {\n            type: \"timeline\",\n            steps: [\n                {\n                    step: \"1\",\n                    title: \"Configurar filtros en Apollo\",\n                    detail: 'Us\\xe1 tu Ficha de Cliente Ideal. T\\xedtulo: \"Owner\" o \"Founder\". Industria: la tuya. Ubicaci\\xf3n: ciudades target en USA. Tama\\xf1o: 1-50 empleados.'\n                },\n                {\n                    step: \"2\",\n                    title: \"Revisar resultados\",\n                    detail: \"Scrolle\\xe1 los primeros 50-100 resultados. \\xbfSe ven como tu cliente ideal? \\xbfLos t\\xedtulos son correctos? Si no, ajust\\xe1 los filtros antes de exportar.\"\n                },\n                {\n                    step: \"3\",\n                    title: \"Exportar 2,500 contactos\",\n                    detail: \"No m\\xe1s, no menos para empezar. Es suficiente para probar tu mensaje sin quemar toda tu munici\\xf3n si necesit\\xe1s ajustes.\"\n                },\n                {\n                    step: \"4\",\n                    title: \"Verificar en MillionVerifier\",\n                    detail: 'Sub\\xed el CSV. Quedate SOLO con los marcados como \"Good\" o \"Valid\". Vas a perder 10-20% de contactos, pero es mejor 2,000 buenos que 2,500 con rebotes.'\n                },\n                {\n                    step: \"5\",\n                    title: \"Dividir en batches de 500\",\n                    detail: \"Batch 1: Restaurantes Miami. Batch 2: Restaurantes Houston. As\\xed pod\\xe9s ver qu\\xe9 ciudad responde mejor y ajustar sin perder toda la lista.\"\n                }\n            ]\n        },\n        {\n            type: \"callout\",\n            variant: \"brand\",\n            content: \"Ley de oro de las listas: 500 emails mandados a las personas correctas generan m\\xe1s clientes que 5,000 emails mandados sin criterio. La precisi\\xf3n siempre gana sobre el volumen.\"\n        }\n    ],\n    \"leccion-5-4\": [\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Los 5 principios del cold email que funciona\"\n        },\n        {\n            type: \"number_breakdown\",\n            numbers: [\n                {\n                    num: \"1\",\n                    label: \"Parec\\xe9 persona, no empresa\",\n                    detail: \"Texto plano. Sin logos, colores, im\\xe1genes, ni firmas elaboradas. Un email que cualquier persona normal mandar\\xeda desde Gmail. Los filtros odian el HTML de marketing.\"\n                },\n                {\n                    num: \"2\",\n                    label: \"El asunto es todo\",\n                    detail: 'Corto, espec\\xedfico, personal. \"pregunta r\\xe1pida\" > \"\\xa1Oferta especial de marketing digital!\". Si tu asunto parece que lo escribi\\xf3 un departamento de marketing, reescrib\\xedlo.'\n                },\n                {\n                    num: \"3\",\n                    label: \"Primera l\\xednea habla de ELLOS\",\n                    detail: '\"Hola, soy Jose Angel y ofrecemos...\" → basura. \"Vi que tu restaurante tiene pocas rese\\xf1as en Google...\" → abre conversaci\\xf3n. Demostr\\xe1 que los investigaste.'\n                },\n                {\n                    num: \"4\",\n                    label: \"Un email, un objetivo\",\n                    detail: \"Tu cold email no cierra ventas. Solo abre puertas. Una sola acci\\xf3n: \\xbfest\\xe1n abiertos a conversar? Nada m\\xe1s. No PDFs, no propuestas, no precios.\"\n                },\n                {\n                    num: \"5\",\n                    label: \"CTA de bajo compromiso\",\n                    detail: '\"\\xbfEstar\\xedas abierto a una conversaci\\xf3n r\\xe1pida de 15 minutos?\" > \"Agend\\xe1 una llamada de 45 minutos para presentaci\\xf3n completa\". Menos compromiso = m\\xe1s respuestas.'\n                }\n            ]\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Framework 1: El email de observaci\\xf3n\"\n        },\n        {\n            type: \"example\",\n            content: \"Asunto: {{firstName}}, algo que not\\xe9 sobre {{companyName}}\\n\\nHola {{firstName}},\\n\\nEstaba revisando {{companyName}} y not\\xe9 que [observaci\\xf3n espec\\xedfica: pocas rese\\xf1as en Google / perfil de Instagram sin actividad reciente / p\\xe1gina web sin versi\\xf3n m\\xf3vil].\\n\\nTrabajo con [tipo de negocio] en [ciudad/contexto] y les ayudo a [resultado espec\\xedfico].\\n\\n\\xbfEstar\\xedas abierto a que te cuente c\\xf3mo funciona? Sin compromiso, solo una conversaci\\xf3n r\\xe1pida.\\n\\n[Tu nombre]\\n\\n───────────────────────────────\\n\\xbfPor qu\\xe9 funciona?\\n• La observaci\\xf3n espec\\xedfica prueba que no es spam masivo\\n• El resultado habla de lo que quieren, no de lo que vend\\xe9s\\n• El CTA es de m\\xednimo compromiso: solo una conversaci\\xf3n\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Framework 2: El email directo\"\n        },\n        {\n            type: \"example\",\n            content: \"Asunto: idea para {{companyName}}\\n\\nHola {{firstName}},\\n\\nTrabajo con [tipo de negocio] en [ciudad] que tienen [problema espec\\xedfico].\\n\\nLes ayudo a [resultado concreto] usando [m\\xe9todo en una frase].\\n\\n\\xbfTe interesa saber c\\xf3mo funciona?\\n\\n[Tu nombre]\\n\\n───────────────────────────────\\n\\xbfCu\\xe1ndo usar cada uno?\\n\\n• Email de Observaci\\xf3n → listas de menos de 500, cuando pod\\xe9s dedicar 30 seg a mirar cada negocio\\n• Email Directo → listas grandes, cuando necesit\\xe1s escalar. Compens\\xe1 con dolor muy espec\\xedfico\"\n        },\n        {\n            type: \"heading\",\n            level: 2,\n            content: \"Errores que matan tus emails\"\n        },\n        {\n            type: \"checklist_inline\",\n            items: [\n                \"P\\xe1rrafos largos — tu email completo deber\\xeda tener 50-100 palabras m\\xe1ximo\",\n                'Lenguaje corporativo — \"Me dirijo a usted para presentarle nuestra propuesta de valor\" → no',\n                \"Adjuntos en el primer email — los filtros los detectan y van a spam\",\n                \"Negritas, colores, HTML — parec\\xe9 persona, no newsletter\",\n                'Empezar con \"Estimado se\\xf1or\" — empez\\xe1 con \"Hola {{firstName}}\"',\n                \"Pedir demasiado en el primer contacto — agenda de 45 min, propuesta completa, etc.\"\n            ]\n        }\n    ]\n};\n// ─────────────────────────────────────────────\n// MAPA: slug de módulo → contenido\n// ─────────────────────────────────────────────\nconst LESSON_CONTENT_MAP = {\n    \"modulo-1-mentalidad\": MODULE_1_CONTENT,\n    \"modulo-2-nicho\": MODULE_2_CONTENT,\n    \"modulo-3-oferta\": MODULE_3_CONTENT,\n    \"modulo-4-incorporacion\": MODULE_4_CONTENT,\n    \"modulo-5-clientes\": MODULE_5_CONTENT\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/lib/lesson-content.ts\n");

